distance = int(input("Enter the distance traveled (in meters): ")) #taking input from the user and converting it to an integer
time = int(input("Enter the time taken (in seconds): ")) #taking input from the user and converting it to an integer
speed = distance / time #calculating the speed using the formula speed = distance / time        
print("The speed of the object is:", speed, "m/s") #printing the speed of the object in meters per second